import {normalizedArticles} from '../fixtures'
import {ADD_COMMENT, DELETE_ARTICLE} from '../types'
import {arrToMap} from '../utils'
import {Map, fromJS, Record} from 'immutable'

const ArticleRecord = Record({
    id: null,
    text: null,
    title: null,
    date: null,
    comments: []
})

export default function (articles = arrToMap(normalizedArticles, ArticleRecord), action) {
    const {type, payload, randomId} = action

    switch (type) {
        case DELETE_ARTICLE:
            /*const articlesCopy = {...articles}
            delete articlesCopy[payload.id]
            return articlesCopy*/
            
            return articles.delete(payload.id)
        case ADD_COMMENT:
            /*const article = articles[payload.articleId]
            const comments = article.comments || []
            return {
                ...articles,
                [payload.articleId]: {
                    ...article,
                    comments: [...comments, randomId]
                }
            }*/

            return articles.updateIn([payload.articleId, 'comments'], (comments) => comments.push(randomId))
        default:
            return articles
    }
}
